const Default = () => <DsAutocomplete
    onValueChange={fn()}
    onInputValueChange={fn()}
    options={mockOptions}
    showTrigger
    placeholder="Select or type to search..."
    style={{ width: '300px' }} />;

const SearchMode = () => <DsAutocomplete
    onValueChange={fn()}
    onInputValueChange={fn()}
    options={mockOptions}
    showTrigger={false}
    placeholder="Start typing to search..."
    style={{ width: '300px' }} />;

const SearchWithIcon = () => <DsAutocomplete
    onValueChange={fn()}
    onInputValueChange={fn()}
    options={countries}
    showTrigger={false}
    startAdornment={<DsIcon icon="search" size="medium" aria-label="search icon" />}
    placeholder="Search countries..."
    style={{ width: '300px' }} />;

const AsyncSearch = () => {
    const [options, setOptions] = useState<DsAutocompleteOption[]>([]);
    const [loading, setLoading] = useState(false);

    const handleInputValueChange = async (value: string) => {
        args.onInputValueChange?.(value);

        if (!value) {
            setOptions([]);
            return;
        }

        setLoading(true);
        const results = await fetchCountries(value);
        setOptions(results);
        setLoading(false);
    };

    return (
        <DsAutocomplete
            onValueChange={fn()}
            options={options}
            loading={loading}
            onInputValueChange={handleInputValueChange}
            showTrigger={false}
            startAdornment={<DsIcon icon="search" size="medium" aria-label="search icon" />}
            placeholder="Search countries (async)..."
            locale={{ noMatches: 'No results found' }}
            style={{ width: '300px' }} />
    );
};

const AsyncOptions = () => {
    const [options, setOptions] = useState<DsAutocompleteOption[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        void fetchAllCountries().then((results) => {
            setOptions(results);
            setLoading(false);
        });
    }, []);

    return (
        <DsAutocomplete
            onValueChange={fn()}
            onInputValueChange={fn()}
            options={options}
            loading={loading}
            placeholder="Select a country..."
            style={{ width: '300px' }} />
    );
};

