const WithEmptyBubble = function WithEmptyBubbleStory() {
    const [isOpen, setIsOpen] = useState(false);
    const [value, setValue] = useState('');
    const [actionRequired, setActionRequired] = useState(false);
    const [comment, setComment] = useState<CommentData | undefined>(undefined);

    const handleSend = (content: string, isActionRequired: boolean) => {
        if (!comment) {
            const newComment: CommentData = {
                id: 'comment-1',
                numericId: 42,
                author: currentUser,
                createdAt: new Date(),
                isResolved: false,
                messages: [
                    {
                        id: 'msg-1',
                        author: currentUser,
                        content,
                        createdAt: new Date(),
                        isInitialMessage: true,
                    },
                ],
            };
            setComment(newComment);
            setActionRequired(isActionRequired);
        } else {
            const newMessage = {
                id: `msg-${String(Date.now())}`,
                author: currentUser,
                content,
                createdAt: new Date(),
            };

            setComment((prev) => {
                if (!prev) {
                    return prev;
                }
                return {
                    ...prev,
                    messages: [...prev.messages, newMessage],
                };
            });
        }
        setValue('');
    };

    const handleEditMessage = (messageId: string, newContent: string) => {
        if (!comment) {
            return;
        }
        setComment((prev) => {
            if (!prev) {
                return prev;
            }
            return {
                ...prev,
                messages: prev.messages.map((msg) =>
                    msg.id === messageId ? { ...msg, content: newContent } : msg,
                ),
            };
        });
    };

    const handleDeleteMessage = (messageId: string) => {
        if (!comment) {
            return;
        }
        setComment((prev) => {
            if (!prev) {
                return prev;
            }
            return {
                ...prev,
                messages: prev.messages.filter((msg) => msg.id !== messageId),
            };
        });
