                        </DsDropdownMenu.Item>
                        <DsDropdownMenu.Item value="preferences">
                            <DsIcon icon="settings" />
                            <span>Preferences</span>
                        </DsDropdownMenu.Item>
                        <DsDropdownMenu.Item value="notifications">
