	const items = Array.from({ length: count }, (_, i) => (
		<div key={i} className={direction === 'horizontal' ? styles.contentItemHorizontal : styles.contentItem}>
			<h3>Item {i + 1}</h3>
			<p>Content for item {i + 1}</p>
